    \ENDFOR
    \STATE $\mathbf{H}_{i} \leftarrow$ Select top-$k$ HyperNodes from $\mathcal{C}_{cand}$ with minimal dist
\ENDFOR
\STATE $\mathbf{H}_{final} \leftarrow \mathbf{H}_{N}$
\STATE \textbf{return} $\mathbf{H}_{final}$
\end{algorithmic}
