\begin{algorithm}[!tb]
\caption{Modality-Aware Expert Routing}
\label{alg:modality_aware_routing}
\begin{algorithmic}[1]
\STATE \textbf{Input:} Token representation $\mathbf{h}_t$, modality indicator $\mathbf{m}_t$, gating weights $\mathbf{W}_g$, expert groups $\mathcal{E}_{text}$, $\mathcal{E}_{audio}$, number of experts to select $K$
\STATE \textbf{Output:} Routed output $\mathbf{y}_{routed, t}$

\STATE \textbf{Step 1: Compute Raw Gating Scores}
\STATE $\mathbf{s}_t \leftarrow \text{softmax}(\mathbf{h}_t W_g) \in \mathbb{R}^N$ \ALGCOMMENT{Raw scores over all $N$ experts}

\STATE \textbf{Step 2: Create Modality-Specific Mask}
\FOR{$i = 1$ to $N$}
    \IF{$m_t = 0$ (text) and $E_i \in \mathcal{E}_{text}$}
        \STATE $M_{m_t, i} \leftarrow 1$
    \ELSIF{$m_t = 1$ (audio) and $E_i \in \mathcal{E}_{audio}$}
        \STATE $M_{m_t, i} \leftarrow 1$
    \ELSE
        \STATE $M_{m_t, i} \leftarrow 0$
    \ENDIF
\ENDFOR

\STATE \textbf{Step 3: Apply Modality Mask}
\STATE $\mathbf{s}'_t \leftarrow \mathbf{s}_t \odot \mathbf{M}_{m_t}$ \ALGCOMMENT{Element-wise multiplication}

\STATE \textbf{Step 4: Select Top-K Experts}
\STATE $\mathcal{I}_t \leftarrow \text{TopK}(\mathbf{s}'_t, K)$ \ALGCOMMENT{Indices of top-K experts}
\STATE $\mathbf{w}'_t \leftarrow \{\mathbf{s}'_t[i] : i \in \mathcal{I}_t\}$ \ALGCOMMENT{Corresponding weights}

\STATE \textbf{Step 5: Compute Routed Output}
